// Device Configuration component for client mode
const DeviceConfiguration: React.FC<{ settings: any; onUpdate: (updates: Record<string, any>) => void }> = ({ settings, onUpdate }) => {
  return (
    <div style={{
      backgroundColor: '#ffffff',
      border: '1px solid #dee2e6',
      borderRadius: '6px',
      padding: '16px'
    }}>
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '12px' }}>
        <h4 style={{ margin: 0, fontSize: '14px', fontWeight: '600', color: '#495057' }}>
          Remote Devices ({(settings.devices || []).length})
        </h4>
        <button
          onClick={() => {
            const newDevice = {
              name: `Device-${Date.now()}`,
              ip: '192.168.1.100',
              port: 502,
              slaveId: 1,
              registers: {
                holdingRegisters: { start: 0, count: 100 },
                coils: { start: 0, count: 64 },
                inputRegisters: { start: 0, count: 50 }
              }
            };
            onUpdate({
              devices: [...(settings.devices || []), newDevice]
            });
          }}
          style={{
            padding: '4px 8px',
            fontSize: '11px',
            backgroundColor: '#28a745',
            color: 'white',
            border: 'none',
            borderRadius: '4px',
            cursor: 'pointer'
          }}
        >
          + Add Device
        </button>
      </div>

      {(settings.devices || []).map((device: any, index: number) => (
        <div
          key={index}
          style={{
            border: '1px solid #e9ecef',
            borderRadius: '4px',
            padding: '12px',
            marginBottom: '8px',
            backgroundColor: '#f8f9fa'
          }}
        >
          <div style={{ display: 'grid', gridTemplateColumns: '2fr 1fr 1fr 1fr auto', gap: '8px', alignItems: 'center' }}>
            <input
              type="text"
              value={device.name}
              onChange={(e) => {
                const updatedDevices = [...(settings.devices || [])];
                updatedDevices[index] = { ...device, name: e.target.value };
                onUpdate({ devices: updatedDevices });
              }}
              placeholder="Device name"
              style={{
                padding: '6px 8px',
                border: '1px solid #ced4da',
                borderRadius: '3px',
                fontSize: '11px'
              }}
            />
            
            <input
              type="text"
              value={device.ip}
              onChange={(e) => {
                const updatedDevices = [...(settings.devices || [])];
                updatedDevices[index] = { ...device, ip: e.target.value };
                onUpdate({ devices: updatedDevices });
              }}
              placeholder="IP Address"
              style={{
                padding: '6px 8px',
                border: '1px solid #ced4da',
                borderRadius: '3px',
                fontSize: '11px'
              }}
            />
            
            <input
              type="number"
              value={device.port}
              onChange={(e) => {
                const updatedDevices = [...(settings.devices || [])];
                updatedDevices[index] = { ...device, port: parseInt(e.target.value) || 502 };
                onUpdate({ devices: updatedDevices });
              }}
              placeholder="Port"
              style={{
                padding: '6px 8px',
                border: '1px solid #ced4da',
                borderRadius: '3px',
                fontSize: '11px'
              }}
            />
            
            <input
              type="number"
              value={device.slaveId}
              onChange={(e) => {
                const updatedDevices = [...(settings.devices || [])];
                updatedDevices[index] = { ...device, slaveId: parseInt(e.target.value) || 1 };
                onUpdate({ devices: updatedDevices });
              }}
              placeholder="Slave ID"
              style={{
                padding: '6px 8px',
                border: '1px solid #ced4da',
                borderRadius: '3px',
                fontSize: '11px'
              }}
            />
            
            <button
              onClick={() => {
                const updatedDevices = (settings.devices || []).filter((_: any, i: number) => i !== index);
                onUpdate({ devices: updatedDevices });
              }}
              style={{
                padding: '4px 6px',
                fontSize: '10px',
                backgroundColor: '#dc3545',
                color: 'white',
                border: 'none',
                borderRadius: '3px',
                cursor: 'pointer'
              }}
            >
              ×
            </button>
          </div>
        </div>
      ))}
    </div>
  );
};

// Register Map Configuration for server mode
const RegisterMapConfiguration: React.FC<{ settings: any; onUpdate: (updates: Record<string, any>) => void }> = ({ settings, onUpdate }) => {
  const registerMap = settings.registerMap || {
    holdingRegisters: { start: 0, count: 1000, access: 'rw' },
    coils: { start: 0, count: 1000, access: 'rw' },
    inputRegisters: { start: 0, count: 1000, access: 'r' },
    discreteInputs: { start: 0, count: 1000, access: 'r' }
  };

  const updateRegisterMap = (type: string, updates: any) => {
    onUpdate({
      registerMap: {
        ...registerMap,
        [type]: { ...registerMap[type], ...updates }
      }
    });
  };

  return (
    <div style={{
      backgroundColor: '#ffffff',
      border: '1px solid #dee2e6',
      borderRadius: '6px',
      padding: '16px'
    }}>
      <h4 style={{ margin: '0 0 12px 0', fontSize: '14px', fontWeight: '600', color: '#495057' }}>
        Register Map Configuration
      </h4>
      
      <div style={{ display: 'grid', gap: '12px' }}>
        {/* Holding Registers */}
        <div style={{
          border: '1px solid #e9ecef',
          borderRadius: '4px',
          padding: '12px',
          backgroundColor: '#f8f9fa'
        }}>
          <h5 style={{ margin: '0 0 8px 0', fontSize: '12px', fontWeight: '600', color: '#495057' }}>
            Holding Registers (Read/Write)
          </h5>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: '8px' }}>
            <div>
              <label style={{ display: 'block', fontSize: '10px', fontWeight: '500', color: '#6c757d', marginBottom: '2px' }}>
                Start Address
              </label>
              <input
                type="number"
                value={registerMap.holdingRegisters.start}
