// Helper Functions
function getDefaultProtocolSettings(type: ProtocolConfig['type']): Record<string, any> {
  switch (type) {
    case 'modbus-tcp':
      return {
        port: 502,
        timeout: 5000,
        retries: 3,
        devices: []
      };
    case 'opcua':
      return {
        endpoint: 'opc.tcp://localhost:4840',
        securityMode: 'None',
        securityPolicy: 'None'
      };
    case 'mqtt':
      return {
        broker: 'mqtt://localhost:1883',
        clientId: 'gateway-client',
        topics: []
      };
    default:
      return {};
  }
}

export default GatewayBuilder;
